#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N*sizeof(long long));
        long long sum=0;
        for(int i=0;i<N;i++){ scanf("%lld", &a[i]); sum+=a[i]; }
        if(sum==0){ printf("0\n"); free(a); continue; }
        int best=1; // at least one segment
        for(int k=N;k>=2;k--){
            if(sum%k!=0) continue;
            long long target = sum/k;
            long long cur=0; int ok=1;
            for(int i=0;i<N;i++){
                cur+=a[i];
                if(cur==target) cur=0;
                else if((target>0 && cur>target) || (target<0 && cur<target)) { ok=0; break; }
            }
            if(ok && cur==0){ best=k; break; }
        }
        printf("%d\n", N-best);
        free(a);
    }
    return 0;
}

