import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] a = new long[N];
            long sum = 0;
            for (int i = 0; i < N; i++) { a[i] = fs.nextLong(); sum += a[i]; }
            if (sum == 0) { sb.append(0).append('\n'); continue; }
            int best = 1;
            for (int k = N; k >= 2; k--) {
                if (sum % k != 0) continue;
                long target = sum / k;
                long cur = 0; boolean ok = true;
                for (long v : a) {
                    cur += v;
                    if (cur == target) cur = 0;
                    else if ((target > 0 && cur > target) || (target < 0 && cur < target)) { ok = false; break; }
                }
                if (ok && cur == 0) { best = k; break; }
            }
            sb.append(N - best).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

