import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        S = sum(a)
        if S == 0:
            out.append('0')
            continue
        best = 1
        for k in range(N, 1, -1):
            if S % k:
                continue
            target = S // k
            cur = 0
            ok = True
            for v in a:
                cur += v
                if cur == target:
                    cur = 0
                elif (target > 0 and cur > target) or (target < 0 and cur < target):
                    ok = False
                    break
            if ok and cur == 0:
                best = k
                break
        out.append(str(N - best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

